export function getCategoryById(id) { return railwayData.find(c => c.id === id); }

export function getAllSignals() {
  return railwayData.flatMap(c => c.signals.map(s => ({ ...s, categoryId: c.id, categoryTitle: c.title, categoryIcon: c.icon })));
}

export function normalizeSearch(text) {
  return (text || "").toLowerCase().normalize("NFD").replace(/\p{M}/gu, "");
}

export function searchExamQuestions(query, categoryId = null) {
  const terms = normalizeSearch(query).split(/\s+/).filter(t => t.length >= 2);
  if (!terms.length) return [];
  return examBank.filter(item => {
    if (categoryId && item.categoryId !== categoryId) return false;
    const hay = normalizeSearch(`${item.num} ${item.question} ${item.answer}`);
    return terms.every(term => hay.includes(term));
  });
}